def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 5:
            score -= 300 * (ratio - 5)**5 + 80 * np.sin(ratio * np.pi * 1.2)
            for j in range(1, 5):
                score += np.log1p(ratio**j) / (j * 1.5)
            if capacity % 11 == 0:
                score -= 50 * np.tanh(ratio)
        elif 4 < ratio <= 5:
            score -= 150 * (ratio - 4.5)**4 + 40 * np.cos(ratio * 6)
            for k in range(1, 6):
                if k % 2 == 1:
                    score += np.exp(-ratio * k) / (k ** 0.9)
                else:
                    score -= np.sin(ratio * k * 0.7) / (k ** 1.3)
            if capacity % 5 == 0:
                score += 20 * np.sin(ratio * capacity / 10)
        elif 3 < ratio <= 4:
            score -= 100 * (ratio - 3)**3 + 30 * np.sin(ratio * 4.5)
            for l in range(1, 7):
                score += ((-1)**l) * np.cos((ratio + l) * np.pi / 3) / (l ** 2)
            if capacity % 9 == 0:
                score += 15 * np.log1p(capacity / (ratio + 1))
        elif 2 < ratio <= 3:
            score -= 70 * (ratio - 2)**2.5 + 25 * np.cos(ratio * 7.5)
            for m in range(1, 6):
                if m % 3 == 0:
                    score += np.tanh(ratio * m) * m / 5
                else:
                    score -= np.exp(-ratio * m) / (m * 3)
            if bin(int(capacity)).count('1') % 2 == 0:
                score += 10
        elif 1 < ratio <= 2:
            val = (ratio - 1) ** 2.3
            score -= 50 * val + 20 * np.sin(ratio * 9)
            for n in range(1, 5):
                score += ((-1) ** n) * np.sin(ratio * np.pi * n * 1.1) / (n ** 1.7)
            if capacity % 6 == 0:
                score -= 12 * np.sqrt(abs(ratio - 1.5))
        else:
            step = 0.1
            added = False
            for p in range(1, 15):
                threshold = p * step
                if ratio < threshold:
                    score += (p ** 5) / (threshold - ratio + 1e-15)
                    added = True
                    break
            if not added:
                score += 8 * (1 - ratio)**3 + 7 * np.cos(ratio * 15)
            for q in range(2, 8):
                score -= np.sin(q * ratio * np.pi / 2) / (q ** 2)
        penalty = 0
        for x in range(1, 9):
            base = ((-1) ** x) * (ratio ** (2 * x)) / (x * 5)
            if x % 4 == 0:
                penalty += base * np.log1p(x + ratio)
            elif x % 2 == 0:
                penalty += base / (1 + np.exp(-x * ratio))
            else:
                penalty -= base * np.exp(-ratio * x / 2)
        score += penalty
        if item > capacity:
            score -= 200
            for m in range(1, 8):
                if capacity == 0:
                    break
                mod_val = item % (capacity + m)
                score += (mod_val ** 0.8) / (m ** 0.6)
                if mod_val > capacity * 0.7:
                    score -= 30 / m
                if (capacity + m) % 2 == 0:
                    score += np.tanh(mod_val / (m + 1))
        elif (capacity - item) < 0.3 * capacity:
            score += 40
            for n in range(6):
                if capacity == 0:
                    break
                score += (capacity - item) * np.cos((n+1) * ratio * 2.5 * np.pi) / (n+1)
                if (capacity - item) < 0.15 * capacity:
                    score += 6 * np.sin((n+1) * ratio * 3.5)
        else:
            if ratio < 0.25:
                score -= 15 * np.exp(-ratio * 25) + 5 * np.cos(ratio * 30)
                for p in range(1, 7):
                    score += np.sin(ratio * np.pi * p * 1.3) / (p ** 3)
        if capacity % 10 == 0:
            score += 5 * (np.log1p(capacity) - ratio * 1.2) + np.sin(ratio * capacity * 1.1)
        elif capacity % 6 == 0:
            score -= 6 * np.sqrt(abs(ratio - 0.6)) + np.cos((capacity + ratio * 1.3) * 4)
        else:
            for q in range(1, 10):
                if (capacity + q) % 5 == 0:
                    score += 0.8 * q / (1 + ratio * q) + 0.3 * np.sin(q * ratio * 1.2)
                else:
                    score -= 0.4 * np.cos(q * ratio * 1.1) / (q + 2)
        if int(capacity) % 3 == 0 and ratio < 0.4:
            for r in range(1, 7):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 0.9) / (r + 0.5)
        if ratio > 3 and capacity > 60:
            factor = 2.0
            for s in range(2, 7):
                score -= factor * np.exp((ratio - s)/s) / (s ** 1.2)
        if ratio > 0.5 and ratio < 1.5 and capacity > 20:
            for t in range(1, 5):
                score += np.cos(ratio * t * np.pi) / (t + 0.3)
                if int(capacity) % t == 0:
                    score += np.sin(capacity / (t + 1))
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    min_priority = np.min(finite_priorities)
    if max_priority == min_priority:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    else:
        normalized = (priorities - min_priority) / (max_priority - min_priority)
        return np.where(np.isfinite(priorities), normalized, -np.inf)
